mapper.select:
SELECT a.id, a.project_id AS "projectId", a.stage_id AS "stageId", a.inspection_items AS "inspectionItems", a.plan_inspection_time AS "planInspectionTime", a.site_photos AS "sitePhotos", a.participants, a.signatures, a.passed_at AS "passedAt", a.acceptance_comments AS "acceptanceComments", a.remark, a.status, a.created_by AS "createdBy", a.created_at AS "createdAt", a.updated_by AS "updatedBy", a.updated_at AS "updatedAt", p.code AS "projectCode", p.name AS "projectName", s.stage_name AS "stageName" FROM inspection a LEFT JOIN project p ON p.id = a.project_id LEFT JOIN project_stage s ON s.id = a.stage_id
AND a.project_id = #{params.projectId}
AND p.name LIKE CONCAT('%', #{params.projectName}, '%') AND p.name LIKE '%' || #{params.projectName} || '%'
AND a.status = #{params.status} AND a.plan_inspection_time >= #{params.startDate} AND a.plan_inspection_time <= #{params.endDate}
ORDER BY a.plan_inspection_time DESC, a.id DESC
